def main(args):
    import json
    import math

    # --- Hidden Math Utilities ---
    def mean(v): 
        return sum(v) / len(v) if v else 0

    def get_rsi(closes, p=14):
        if len(closes) < p + 1: return 50
        diffs = [closes[i] - closes[i-1] for i in range(1, len(closes))]
        avg_g = mean([d for d in diffs[-p:] if d > 0])
        avg_l = mean([-d for d in diffs[-p:] if d < 0])
        if avg_l == 0: return 100
        return 100 - (100 / (1 + (avg_g / avg_l)))

    def get_hurst(ts):
        lags = range(2, 20)
        tau = []
        for lag in lags:
            diffs = [ts[j] - ts[j-lag] for j in range(lag, len(ts))]
            if not diffs: 
                tau.append(0)
                continue
            m = mean(diffs)
            v = sum((x - m)**2 for x in diffs) / len(diffs)
            tau.append(math.sqrt(math.sqrt(v)))
        log_l = [math.log(l) for l in lags]
        log_t = [math.log(t) if t > 0 else 0 for t in tau]
        n = len(log_l)
        denom = (n * sum(x**2 for x in log_l) - sum(log_l)**2)
        slope = (n * sum(log_l[i] * log_t[i] for i in range(n)) - sum(log_l) * sum(log_t)) / denom if denom != 0 else 0
        return slope * 2.0

    def analyze_vibe(closes, highs, lows):
        h_val = get_hurst(closes)
        r_val = get_rsi(closes)

        # Volatility as "Adrenaline"
        tr = [highs[i]-lows[i] for i in range(len(closes))]
        adr = (mean(tr[-14:]) / closes[-1]) * 100 if closes[-1] else 0

        # Translate Math to Narrative
        if h_val > 0.6: 
            vibe = "Locked in a powerful trend"
            mood = "Determined"
        elif h_val < 0.45: 
            vibe = "Snapping back like a rubber band"
            mood = "Elastic"
        else: 
            vibe = "Drifting aimlessly"
            mood = "Indecisive"

        if r_val > 70: 
            energy = "Euphoric / Overextended"
        elif r_val < 30: 
            energy = "Exhausted / Depressed"
        else: 
            energy = "Balanced and calm"

        return {
            "ticker": "",
            "price": f"${closes[-1]:.2f}",
            "market_soul": {
                "vibe": vibe,
                "mood": mood,
                "energy": energy,
                "adrenaline_level": "High" if adr > 2 else "Chilled"
            },
            "raw_signal": "Bullish" if (h_val > 0.5 and r_val < 60) else "Bearish" if (h_val > 0.5 and r_val > 40) else "Neutral"
        }

    # --- Input Handling & Parsing ---
    raw_in = args.params.get('input', '{}')
    raw = {}
    if isinstance(raw_in, str):
        # Scrub markdown formatting if present
        clean = raw_in.replace("```json", "").replace("```", "").strip()
        try:
            raw = json.loads(clean)
        except:
            try:
                import ast
                raw = ast.literal_eval(clean)
            except: 
                raw = {}
    else: 
        raw = raw_in

    # --- Recursive Search for Data ---
    def find_bars(obj):
        if not isinstance(obj, dict): return None
        # Direct check for 'bars' key
        if "bars" in obj and isinstance(obj["bars"], dict): 
            return obj["bars"]
        # Check if the dictionary itself is a map of tickers to bar lists
        for k, v in obj.items():
            if isinstance(v, list) and v and isinstance(v[0], dict) and ('c' in v[0] or 'close' in v[0]): 
                return obj
            # Dig deeper
            res = find_bars(v)
            if res: return res
        return None

    bars_map = find_bars(raw) or {}
    results = []

    # --- Processing ---
    if isinstance(bars_map, dict):
        for ticker, bars in bars_map.items():
            if not isinstance(bars, list) or len(bars) < 20: 
                continue
            try:
                # Sort by time to ensure calculations are correct
                b_sorted = sorted(bars, key=lambda x: x.get('t', 0))
                c = [float(x.get('c', x.get('close', 0))) for x in b_sorted]
                h = [float(x.get('h', x.get('high', 0))) for x in b_sorted]
                l = [float(x.get('l', x.get('low', 0))) for x in b_sorted]

                analysis = analyze_vibe(c, h, l)
                analysis["ticker"] = ticker
                results.append(analysis)
            except: 
                continue

    return {'result': json.dumps(results)}
